// TDD Test Runner for Validate & Format logic
// Tests all 7 income/expense classification scenarios

const OWNERS = ['HOANG NHAT HOANG', 'LE THI THANH DUNG'];

function validateAndFormat(body, src) {
  const chatId = src.chat_id;
  if (body.error) return { valid: false, reason: 'Không thể đọc ảnh.', chat_id: chatId };

  const d = body.data || {};
  const missing = [];
  if (d.total_amount == null) missing.push('số tiền');
  if (!d.currency)            missing.push('đơn vị tiền');
  if (!d.date)                missing.push('ngày');
  if (missing.length > 0) return { valid: false, reason: 'Không tìm thấy: ' + missing.join(', '), chat_id: chatId };

  const ocrUpper = String(body.ocr_text || '').toUpperCase();
  const toMatch = ocrUpper.match(/T(?:Ớ|Ơ|O)I\s+T(?:À|A)I\s+KHO(?:À|A)N[:\s]+([A-Z][A-Z0-9\s\(\)_\-]+)/);
  let txType;
  if (toMatch) {
    const receiver = toMatch[1].trim();
    txType = OWNERS.some(o => receiver.includes(o)) ? 'income' : 'expense';
  } else if (/T.I\s+T.I\s+KHO.N/.test(ocrUpper)) {
    txType = d.transaction_type === 'income' ? 'income' : 'expense';
  } else if (/T(?:Ừ|U)\s+T(?:À|A)I\s+KHO(?:À|A)N|NGU(?:Ờ|O)I\s+G(?:Ử|U)I|NGU(?:Ờ|O)I\s+CHUY(?:Ể|E)N/.test(ocrUpper)) {
    txType = 'income';
  } else {
    txType = d.transaction_type === 'income' ? 'income' : 'expense';
  }

  const [y, m, day] = d.date.split('-');
  return {
    valid: true,
    merchant:         d.merchant ? String(d.merchant).slice(0, 255) : null,
    total_amount:     Number(d.total_amount),
    currency:         String(d.currency).toUpperCase().slice(0, 3),
    date:             d.date,
    time:             d.time || null,
    date_display:     (d.time ? d.time + ' ' : '') + day + '/' + m + '/' + y,
    transaction_type: txType,
    owner_name:       txType === 'income' ? (d.merchant || null) : src.sender_name,
  };
}

const MOCK_SRC = { chat_id: 123, sender_id: 661762284, sender_name: 'HOANG NHAT HOANG' };

const TEST_CASES = [
  {
    name: 'Case 1: Outgoing transfer (you to MOMO)',
    input: {
      data: { merchant: 'MOMO_PHUC LOC THO', total_amount: 118000, currency: 'VND', date: '2026-05-01', time: '19:47', transaction_type: 'expense' },
      ocr_text: 'TECHCOMBANK\n-VND 118,000\n19:47 01/05/2026\n\nTu tai khoan\n\nHOANG NHAT HOANG\nTechcombank\n\nToi tai khoan\n\nMOMO_PHUC LOC THO\nVIETCAPITAL BANK'
    },
    expect: { transaction_type: 'expense', merchant: 'MOMO_PHUC LOC THO', owner_name: 'HOANG NHAT HOANG' }
  },
  {
    name: 'Case 2: Incoming to you (sender shown)',
    input: {
      data: { merchant: 'NGUYEN VAN A', total_amount: 500000, currency: 'VND', date: '2026-05-01', time: '10:00', transaction_type: 'expense' },
      ocr_text: 'TECHCOMBANK\n+VND 500,000\n10:00 01/05/2026\n\nTu tai khoan\n\nNGUYEN VAN A\n\nToi tai khoan\n\nHOANG NHAT HOANG\nTechcombank'
    },
    expect: { transaction_type: 'income', merchant: 'NGUYEN VAN A', owner_name: 'NGUYEN VAN A' }
  },
  {
    name: 'Case 3: Cross-bank incoming to you (no sender)',
    input: {
      data: { merchant: null, total_amount: 200000, currency: 'VND', date: '2026-05-01', time: '11:00', transaction_type: 'expense' },
      ocr_text: 'TECHCOMBANK\nVND 200,000\n11:00 01/05/2026\n\nToi tai khoan\n\nHOANG NHAT HOANG\nTechcombank'
    },
    expect: { transaction_type: 'income', merchant: null, owner_name: null }
  },
  {
    name: 'Case 4: Wife sends out (her name hidden)',
    input: {
      data: { merchant: 'NGUYEN VAN B', total_amount: 300000, currency: 'VND', date: '2026-05-01', time: '12:00', transaction_type: 'expense' },
      ocr_text: 'VIETCAPITAL BANK\nVND 300,000\n12:00 01/05/2026\n\nToi tai khoan\n\nNGUYEN VAN B\nSome Bank'
    },
    expect: { transaction_type: 'expense', merchant: 'NGUYEN VAN B', owner_name: 'HOANG NHAT HOANG' }
  },
  {
    name: 'Case 5: Incoming to wife',
    input: {
      data: { merchant: 'TRAN THI C', total_amount: 1000000, currency: 'VND', date: '2026-05-01', time: '13:00', transaction_type: 'expense' },
      ocr_text: 'VIETCAPITAL BANK\n+VND 1,000,000\n13:00 01/05/2026\n\nTu tai khoan\n\nTRAN THI C\n\nToi tai khoan\n\nLE THI THANH DUNG'
    },
    expect: { transaction_type: 'income', merchant: 'TRAN THI C', owner_name: 'TRAN THI C' }
  },
  {
    name: 'Case 6: Missing required fields (invalid)',
    input: {
      data: { merchant: 'SHOP', total_amount: null, currency: 'VND', date: '2026-05-01', transaction_type: 'expense' },
      ocr_text: 'some shop receipt'
    },
    expect: { valid: false }
  },
  {
    name: 'Case 7: Shop receipt (no bank fields)',
    input: {
      data: { merchant: 'HIGHLANDS COFFEE', total_amount: 55000, currency: 'VND', date: '2026-05-01', time: '08:30', transaction_type: 'expense' },
      ocr_text: 'HIGHLANDS COFFEE\nCAM CHUOI TUYET 55,000\nTOTAL 55,000 VND\n08:30 01/05/2026'
    },
    expect: { transaction_type: 'expense', merchant: 'HIGHLANDS COFFEE', owner_name: 'HOANG NHAT HOANG' }
  }
];

const results = [];
let allPassed = true;

for (const tc of TEST_CASES) {
  const out = validateAndFormat(tc.input, MOCK_SRC);
  const errors = [];
  for (const [key, expected] of Object.entries(tc.expect)) {
    const actual = out[key];
    if (actual !== expected) {
      errors.push(`${key}: expected "${expected}", got "${actual}"`);
    }
  }
  const passed = errors.length === 0;
  if (!passed) allPassed = false;
  results.push({ test: tc.name, status: passed ? 'PASS' : 'FAIL', errors: errors.join(' | ') || null });
}

const summary = results.map(r => `${r.status === 'PASS' ? 'PASS' : 'FAIL'} ${r.test}${r.errors ? ' -> ' + r.errors : ''}`).join('\n');

return [{ json: {
  passed: allPassed,
  total: results.length,
  passed_count: results.filter(r => r.status === 'PASS').length,
  failed_count: results.filter(r => r.status === 'FAIL').length,
  results,
  summary
}}];
